SELECT 1 AS Kolejnosc, 'ZaE_GIDTyp' AS CDN_Pole, 'GID elementu zamowienia - typ (staly 960=Zamowienie)' AS Opis_w_dokumentacji, '960' AS Przykladowe_wartosci, '-' AS Alias_w_widoku, '-' AS Transformacja, 'Nie' AS Uwzglednic, 'COUNT DISTINCT=1 (staly 960)' AS Uzasadnienie, '' AS Komentarz_Analityka
