UNION ALL SELECT 6, 'JOIN CDN.ZamNag: Numer_Dokumentu', 'Numer zamowienia', 'ZS-2/05/23/PH_4', 'Numer_Dokumentu', 'INNER JOIN ZamNag; SKROT-Numer/MM/YY/Seria — CASE ZaN_ZamTyp: 640=OFZ, 768=OFS, 1152=ZZ, 1280=ZS, ELSE ZAM', 'Tak', 'INNER JOIN zweryfikowany: COUNT(total=275635) = COUNT(z_join=275635) — 0 sierot', ''
UNION ALL SELECT 7, 'JOIN CDN.ZamNag: ZaN_ZamTyp', 'Typ zamowienia', '640,768,1152,1280', 'Typ_Zamowienia', 'JOIN ZamNag; CASE: 640=Oferta zakupu, 768=Oferta sprzedazy, 1152=Zamowienie zakupu, 1280=Zamowienie sprzedazy, 2688=Zapytanie ofertowe zakupu, 2816=Zapytanie ofertowe sprzedazy, ELSE Nieznane(val)', 'Tak', 'Typ dokumentu zamowienia', ''
UNION ALL SELECT 8, 'JOIN CDN.ZamNag: ZaN_Stan', 'Stan zamowienia', '1,2,3,4,5,21', 'Stan_Zamowienia', 'JOIN ZamNag; CASE: 1=Oferta, 2=Zamowienie, 3=Potwierdzone, 4=Zaakceptowane, 5=W realizacji, 19=Odrzucone, 21=Zrealizowane, 35=Anulowane (potw.), 51=Anulowane (arch.+potw.), 53=Zamkniete w realizacji, ELSE Nieznane(val)', 'Tak', 'Stan realizacji zamowienia', ''
UNION ALL SELECT 9, 'JOIN CDN.ZamNag: ZaN_DataWystawienia', 'Data wystawienia zamowienia', '2023-05-15', 'Data_Wystawienia', 'JOIN ZamNag; Clarion DATE: DATEADD(d, ZaN_DataWystawienia, ''18001228'')', 'Tak', 'Core pole analityczne — data dokumentu', ''
